func protoReadUint32(buf []byte) (uint32, int) {
	data, n := protowire.ConsumeVarint(buf)
	if n < 0 {
		return 0, n
	}
	if data > math.MaxUint32 {
		return 0, -3
	}
	return uint32(data), n
}

